def generate_saml_request():
    request_id = f"_{uuid.uuid4()}"
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    
    saml_request = f'''<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{IDP_SSO_URL}"
    AssertionConsumerServiceURL="{ACS_URL}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{SP_ENTITY_ID}</saml:Issuer>
    <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" AllowCreate="true"/>
</samlp:AuthnRequest>'''
    
    return request_id, saml_request

def encode_saml_request(saml_request):
    compressed = zlib.compress(saml_request.encode('utf-8'))[2:-4]
    encoded = base64.b64encode(compressed).decode('utf-8')
    return encoded

def decode_saml_response(saml_response_b64):
    decoded = base64.b64decode(saml_response_b64)
    return decoded.decode('utf-8')

def parse_saml_assertion(saml_xml):
    root = ET.fromstring(saml_xml)
    
    assertion = root.find('.//saml:Assertion', SAML_NAMESPACES)
    
    if assertion is None:
        return None, "No Assertion found in SAML response"
    
    subject = assertion.find('.//saml:Subject/saml:NameID', SAML_NAMESPACES)
    if subject is None:
        return None, "No Subject found in Assertion"
    
    user_id = subject.text
    
    attribute_statement = assertion.find('.//saml:AttributeStatement', SAML_NAMESPACES)
    attributes = {}
    
    if attribute_statement is not None:
        for attr in attribute_statement.findall('.//saml:Attribute', SAML_NAMESPACES):
            attr_name = attr.get('Name')
            attr_value_elem = attr.find('.//saml:AttributeValue', SAML_NAMESPACES)
            if attr_value_elem is not None and attr_value_elem.text:
                attributes[attr_name] = attr_value_elem.text
    
    conditions = assertion.find('.//saml:Conditions', SAML_NAMESPACES)
    not_before = None
    not_on_or_after = None
    
    if conditions is not None:
        not_before = conditions.get('NotBefore')
        not_on_or_after = conditions.get('NotOnOrAfter')
    
    authn_statement = assertion.find('.//saml:AuthnStatement', SAML_NAMESPACES)
    session_index = None
    if authn_statement is not None:
        session_index = authn_statement.get('SessionIndex')
    
    return {
        'user_id': user_id,
        'attributes': attributes,
        'not_before': not_before,
        'not_on_or_after': not_on_or_after,
        'session_index': session_index,
        'assertion': assertion
    }, None

def validate_assertion_timing(not_before, not_on_or_after):
    now = datetime.utcnow()
    
    if not_before:
        nb_time = datetime.strptime(not_before, '%Y-%m-%dT%H:%M:%SZ')
        if now < nb_time:
            return False, "Assertion not yet valid"
    
    if not_on_or_after:
        nooa_time = datetime.strptime(not_on_or_after, '%Y-%m-%dT%H:%M:%SZ')
        if now >= nooa_time:
            return False, "Assertion has expired"
    
    return True, None

def validate_saml_response(saml_xml, request_id):
    root = ET.fromstring(saml_xml)
    
    status_code = root.find('.//samlp:StatusCode', SAML_NAMESPACES)
    if status_code is None:
        return None, "No StatusCode found in response"
    
    status_value = status_code.get('Value')
    if status_value != 'urn:oasis:names:tc:SAML:2.0:status:Success':
        return None, f"Authentication failed with status: {status_value}"
    
    in_response_to = root.get('InResponseTo')
    if request_id and in_response_to != request_id:
        return None, "InResponseTo does not match request ID"
    
    assertion_data, error = parse_saml_assertion(saml_xml)
    if error:
        return None, error
    
    if assertion_data['not_before'] or assertion_data['not_on_or_after']:
        valid, error = validate_assertion_timing(
            assertion_data['not_before'],
            assertion_data['not_on_or_after']
        )
        if not valid:
            return None, error
    
    return assertion_data, None

@app.route('/')
def index():
    if 'user_id' in session:
        return redirect(url_for('dashboard'))
    return render_template_string(LOGIN_PAGE)

@app.route('/saml/login', methods=['POST'])
def saml_login():
    request_id, saml_request = generate_saml_request()
    
    pending_requests[request_id] = {
        'timestamp': datetime.utcnow(),
        'request': saml_request
    }
    
    encoded_request = encode_saml_request(saml_request)
    
    redirect_url = f"{IDP_SSO_URL}?SAMLRequest={encoded_request}&RelayState=/"
    
    return redirect(redirect_url)

@app.route('/saml/acs', methods=['POST'])
def assertion_consumer_service():
    saml_response_b64 = request.form.get('SAMLResponse')
    relay_state = request.form.get('RelayState', '/')
    
    if not saml_response_b64:
        return jsonify({'error': 'No SAMLResponse provided'}), 400
    
    try:
        saml_xml = decode_saml_response(saml_response_b64)
    except Exception as e:
        return jsonify({'error': f'Failed to decode SAMLResponse: {str(e)}'}), 400
    
    root = ET.fromstring(saml_xml)
    in_response_to = root.get('InResponseTo')
    
    request_id = None
    if in_response_to and in_response_to in pending_requests:
        request_id = in_response_to
        del pending_requests[in_response_to]
    
    assertion_data, error = validate_saml_response(saml_xml, request_id)
    
    if error:
        return jsonify({'error': error}), 400
    
    session.permanent = True
    session['user_id'] = assertion_data['user_id']
    session['saml_session_index'] = assertion_data['session_index']
    session['authenticated'] = True
    session['auth_time'] = datetime.utcnow().isoformat()
    
    user_attributes = assertion_data['attributes']
    session['email'] = user_attributes.get('email', user_attributes.get('mail', assertion_data['user_id']))
    session['name'] = user_attributes.get('name', user_attributes.get('displayName', 'User'))
    session['attributes'] = user_attributes
    
    return redirect(relay_state)

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session:
        return redirect(url_for('index'))
    
    return render_template_string(
        DASHBOARD_PAGE,
        user_id=session.get('user_id'),
        email=session.get('email'),
        name=session.get('name'),
        session_id=session.get('saml_session_index', 'N/A'),
        attributes=session.get('attributes', {})
    )

@app.route('/logout', methods=['POST'])
def logout():
    session.clear()
    return redirect(url_for('index'))

@app.route('/saml/metadata')
def metadata():
    metadata_xml = f'''<?xml version="1.0"?>
<md:EntityDescriptor xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
                     entityID="{SP_ENTITY_ID}">
  <md:SPSSODescriptor protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
    <md:AssertionConsumerService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
                                 Location="{ACS_URL}"
                                 index="0"/>
  </md:SPSSODescriptor>
</md:EntityDescriptor>'''
    return metadata_xml, 200, {'Content-Type': 'application/xml'}

@app.route('/api/session')
def session_info():
    if 'user_id' not in session:
        return jsonify({'authenticated': False}), 401
    
    return jsonify({
        'authenticated': True,
        'user_id': session.get('user_id'),
        'email': session.get('email'),
        'name': session.get('name'),
        'auth_time': session.get('auth_time'),
        'session_index': session.get('saml_session_index')
    })

